import{_ as e,o as i,c as o,ag as n}from"./chunks/framework.ByAj6Cie.js";const u=JSON.parse('{"title":"Distorsión armónica total (THD)","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-quality/thd.md","filePath":"es/power-quality/thd.md"}'),s={name:"es/power-quality/thd.md"};function l(r,a,t,c,d,p){return i(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="distorsion-armonica-total-thd" tabindex="-1">Distorsión armónica total (THD) <a class="header-anchor" href="#distorsion-armonica-total-thd" aria-label="Permalink to &quot;Distorsión armónica total (THD)&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>La distorsión armónica total, o THD, es una medida de cuánto una forma de onda está distorsionada por armónicos en comparación con la frecuencia fundamental.</p><p>Se utiliza comúnmente para cuantificar la calidad de las formas de onda de voltaje o corriente en un sistema de potencia.</p><p>Un valor de THD más alto indica mayor distorsión y menor calidad de energía.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de la THD es:</p><ul><li>Evaluar el nivel de distorsión de la forma de onda en el sistema</li><li>Identificar posibles problemas de calidad de energía</li><li>Apoyar el diseño y la selección de soluciones de mitigación</li><li>Garantizar el cumplimiento de límites de distorsión aceptables</li></ul><p>La THD proporciona una forma sencilla de evaluar el impacto de los armónicos.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>La THD se calcula como la relación entre la suma de todos los componentes armónicos y el componente fundamental.</p><p>Típicamente se expresa como un porcentaje.</p><p>Se utilizan dos formas comunes:</p><ul><li>THD de voltaje</li><li>THD de corriente</li></ul><p>Un valor bajo de THD indica una forma de onda cercana a una onda sinusoidal pura.</p><p>Un valor alto de THD indica distorsión significativa causada por componentes armónicos.</p><p>La THD depende de:</p><ul><li>El número y la magnitud de las frecuencias armónicas presentes</li><li>El tipo de cargas conectadas al sistema</li><li>La impedancia de la red eléctrica</li></ul><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>La THD se utiliza en:</p><ul><li>Monitoreo y análisis de calidad de energía</li><li>Evaluación de sistemas con cargas no lineales</li><li>Diseño y verificación de soluciones de mitigación armónica</li><li>Instalaciones industriales con variadores, convertidores y equipos electrónicos</li><li>Cumplimiento de normas de calidad de energía</li></ul><p>Es un parámetro clave en los sistemas de potencia modernos.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Límites aceptables</strong><br> La THD de voltaje generalmente se mantiene dentro de límites definidos para una operación adecuada</p></li><li><p><strong>Tipo de carga</strong><br> Las cargas no lineales incrementan la distorsión de corriente y pueden afectar la THD de voltaje</p></li><li><p><strong>Robustez del sistema</strong><br> Los sistemas robustos se ven menos afectados por las corrientes armónicas</p></li><li><p><strong>Ubicación de la medición</strong><br> Los valores de THD varían según el punto donde se miden</p></li><li><p><strong>Impacto en el equipo</strong><br> Una THD alta puede causar sobrecalentamiento, pérdidas y mal funcionamiento</p></li><li><p><strong>Métodos de mitigación</strong><br> Los filtros y las mejoras en el diseño del sistema ayudan a reducir la THD</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Una THD de corriente baja no siempre garantiza una THD de voltaje baja</li><li>Niveles altos de THD pueden provocar sobrecalentamiento en transformadores y cables</li><li>Monitorear la THD a lo largo del tiempo ayuda a detectar cambios en el comportamiento del sistema</li><li>Agregar cargas no lineales sin análisis puede degradar la calidad de energía</li><li>La mitigación debe enfocarse en las principales fuentes de distorsión</li></ul>',26)])])}const h=e(s,[["render",l]]);export{u as __pageData,h as default};
